A standard C++ class encapsulating hit points to ensure sanity check validation:

```cpp
class ACharacter {
private:
    float Health = 100.0f;
    float MaxHealth = 100.0f;

public:
    float GetHealth() const { return Health; }

    void ApplyDamage(float Amount) {
        if (Amount <= 0.0f) return;
        Health -= Amount;
        if (Health < 0.0f) {
            Health = 0.0f;
            OnDeath();
        }
    }

protected:
    virtual void OnDeath() {
        // Override in subclasses for ragdolls, sound triggers, etc.
    }
};
```
